  fn main(args: [String]) -> Int {
    let text = args[0];
    let words = text.split(" ");
    let mut wordCounts: [String, Int] = [];

    for word in words {
      let lowerCaseWord = word.toLower();
      let mut found = false;
      for i in 0..wordCounts.len() {
        if wordCounts[i].0 == lowerCaseWord {
          wordCounts[i].1 += 1;
          found = true;
          break;
        }
      }
      if !found {
        wordCounts.push((lowerCaseWord, 1));
      }
    }

    wordCounts.sort_by(|a, b| a.0.cmp(b.0));

    for pair in wordCounts {
      println!("{}: {}", pair.0, pair.1);
    }

    return 0;
  }

