import string

def word_frequency(text):
    """
    Counts the frequency of each word in a text string (case-insensitive)
    and prints each word and its count as "word count" (one per line),
    sorted alphabetically by word.
    """
    word_counts = {}
    text = text.lower()
    text = text.translate(str.maketrans('', '', string.punctuation))
    words = text.split()

    for word in words:
        if word in word_counts:
            word_counts[word] += 1
        else:
            word_counts[word] = 1

    sorted_words = sorted(word_counts.items())

    for word, count in sorted_words:
        print(f"{word} {count}")

if __name__ == "__main__":
    if len(sys.argv) < 2:
        print("Usage: python word_frequency.py \"text string\"")
    else:
        text = " ".join(sys.argv[1:])
        word_frequency(text)

