def evaluate_rpn(expression):
    stack = []
    tokens = expression.split()
    for token in tokens:
        if token == '+':
            operand2 = stack.pop()
            operand1 = stack.pop()
            stack.append(operand1 + operand2)
        elif token == '-':
            operand2 = stack.pop()
            operand1 = stack.pop()
            stack.append(operand1 - operand2)
        elif token == '*':
            operand2 = stack.pop()
            operand1 = stack.pop()
            stack.append(operand1 * operand2)
        elif token == '/':
            operand2 = stack.pop()
            operand1 = stack.pop()
            stack.append(int(operand1 / operand2))
        else:
            try:
                stack.append(int(token))
            except ValueError:
                print("Invalid token:", token)
                return None
    if len(stack) == 1:
        return stack[0]
    else:
        print("Invalid RPN expression")
        return None

